class Solution:
    def removeOuterParentheses(self, s: str) -> str:
        stack = []  # Bu yığın, açılış parantezlerini takip etmek için kullanılır.
        result = []  # Nihai sonucu oluşturan karakterleri depolar.
        current_primitive_chars = [] # Mevcut ilkel parantez dizisinin iç kısmını depolar.

        for char in s:
            if char == '(':
                # Eğer yığın boş değilse, bu açılış parantezi mevcut ilkel dizinin dışındaki parantez değildir.
                # Bu yüzden bu karakteri current_primitive_chars listesine ekleriz.
                if stack:
                    current_primitive_chars.append(char)
                # Her zaman yığına açılış parantezini ekleriz, dengeyi takip etmek için.
                stack.append(char)
            elif char == ')':
                # Her zaman yığından pop yaparız, dengeyi takip etmek için.
                stack.pop()
                # Eğer yığın boş değilse, bu kapanış parantezi mevcut ilkel dizinin dışındaki parantez değildir.
                # Bu yüzden bu karakteri current_primitive_chars listesine ekleriz.
                if stack:
                    current_primitive_chars.append(char)
                else:
                    # Yığın boşsa, bu, mevcut ilkel parantez dizisinin sona erdiği anlamına gelir.
                    # current_primitive_chars listesi, az önce tamamlanan ilkel dizinin iç kısmını içerir.
                    # Bu iç kısmı nihai sonuca ekleriz.
                    result.extend(current_primitive_chars)
                    # Bir sonraki ilkel dizi için current_primitive_chars listesini sıfırlarız.
                    current_primitive_chars = []

        return "".join(result)
